// src/components/home/HomePage.jsx
import React from "react";
import { useNavigate } from "react-router-dom"; // <-- add this import

export default function HomePage() {
  const navigate = useNavigate(); // <-- for real navigation when you want it

  // Helper: fake link that looks exactly like <a> but satisfies a11y
  const FakeLink = ({ children, onClick, className = "" }) => (
    <button
      type="button"
      onClick={(e) => {
        e.preventDefault();
        onClick?.(e);
      }}
      className={`text-sm font-medium hover:text-primary transition-colors ${className}`}
      style={{ background: "none", border: "none", padding: 0, cursor: "pointer", textAlign: "left" }}
    >
      {children}
    </button>
  );

  return (
    <>
      <head>
        <meta charSet="utf-8" />
        <meta name="viewport" content="width=device-width, initial-scale=1.0" />
        <title>TunisiaED - Learn the Skills of Tomorrow</title>

        <script src="https://cdn.tailwindcss.com?plugins=forms,container-queries"></script>
        <link
          href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap"
          rel="stylesheet"
        />
        <link href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined" rel="stylesheet" />

        <script
          dangerouslySetInnerHTML={{
            __html: `
              tailwind.config = {
                darkMode: "class",
                theme: {
                  extend: {
                    colors: {
                      primary: "#0D47A1",
                      secondary: "#D32F2F",
                      accent: "#FFC107",
                      "background-light": "#F5F5F5",
                      "background-dark": "#101922",
                      "text-light": "#333333",
                      "text-dark": "#F5F5F5",
                      "neutral-light": "#F5F5F5",
                      "neutral-dark": "#333333"
                    },
                    fontFamily: { display: ["Inter", "sans-serif"] }
                  }
                }
              }
            `,
          }}
        />

        <style
          dangerouslySetInnerHTML={{
            __html: `.material-symbols-outlined { font-variation-settings: 'FILL' 0, 'wght' 400, 'GRAD' 0, 'opsz' 24; }`,
          }}
        />
      </head>

      <body className="bg-background-light dark:bg-background-dark font-display text-text-light dark:text-text-dark min-h-screen">
        <div className="relative flex min-h-screen w-full flex-col overflow-x-hidden">
          <div className="flex h-full grow flex-col">

            {/* HEADER */}
            <header className="sticky top-0 z-50 border-b border-neutral-light/10 bg-background-light/80 backdrop-blur-sm dark:border-neutral-dark/10 dark:bg-background-dark/80">
              <div className="mx-auto max-w-7xl px-4 lg:px-10">
                <div className="flex h-16 items-center justify-between">
                  <div className="flex items-center gap-4">
                    <svg className="size-8 text-primary" fill="currentColor" viewBox="0 0 48 48">
                      <path d="M8.57829 8.57829C5.52816 11.6284 3.451 15.5145 2.60947 19.7452C1.76794 23.9758 2.19984 28.361 3.85056 32.3462C5.50128 36.3314 8.29667 39.7376 11.8832 42.134C15.4698 44.5305 19.6865 45.8096 24 45.8096C28.3135 45.8096 32.5302 44.5305 36.1168 42.134C39.7033 39.7375 42.4987 36.3314 44.1494 32.3462C45.8002 28.361 46.2321 23.9758 45.3905 19.7452C44.549 15.5145 42.4718 11.6284 39.4217 8.57829L24 24L8.57829 8.57829Z" />
                    </svg>
                    <h2 className="text-xl font-bold tracking-tight">TunisiaED</h2>
                  </div>

                  {/* NAVIGATION – now a11y-safe */}
                  <nav className="hidden lg:flex items-center gap-8">
                    {["Courses", "Roadmaps", "Resources", "Instructors", "Community Forums", "Subscriptions"].map((item) => (
                      <FakeLink key={item} onClick={() => console.log(item + " clicked")}>
                        {item}
                      </FakeLink>
                    ))}
                  </nav>

                  <div className="flex items-center gap-4">
                    {/* Real navigation buttons */}
                    <button
                      onClick={() => navigate("/login")}
                      className="hidden sm:flex h-10 rounded-lg bg-accent px-4 text-sm font-bold text-primary hover:bg-accent/90"
                    >
                      Sign Up
                    </button>
                    <button
                      onClick={() => navigate("/login")}
                      className="hidden sm:flex h-10 rounded-lg bg-neutral-light/80 dark:bg-neutral-dark/80 px-4 text-sm font-bold"
                    >
                      Login
                    </button>

                    <div
                      className="size-10 rounded-full bg-cover"
                      style={{
                        backgroundImage:
                          "url('https://lh3.googleusercontent.com/aida-public/AB6AXuB3LJoYx8Gg5EUsSpZQvHuwtf6CCRIQYsCTOGNrQmrBGF9u-apv4HJLMJglJfRXLL_o_rr-hFrzF4z5d17wwZIx8oNiAG7tp0wn0YMoCI8we3RqClZw7QFC50JA2fBvp3aFV5lhPzLX7SLQU1fEgKUaEKUZB2x8r4mOb1a8gpoms3-G3Tz2LChpnh2yVPOhQhKefA8O__TShe9nzOKuM0QhfjJKExsqWb11KeDgDTdgNzTkU2Ja2f36wqSBzpBecuj-GLwU8shfkg')",
                      }}
